var s = msg.payload;
msg.payload = {entities:s.entities,bandSlots:s.bandSlots,confirmed:s.confirmed,unconfirmed:s.unconfirmed,updated:new Date().toLocaleTimeString()};
msg.topic = 'dxcc_stats';
return msg;

var line = (msg.payload || '').trim();
var src  = msg.topic || 'unknown';

if (line.toLowerCase().includes('login:') || line.toLowerCase().includes('please login')) {
    node.status({ fill:'blue', shape:'dot', text: src + ' → login sent' });
    return [{ payload: 'VU2CPL\r\n', _session: msg._session }, null];
}

if (!line.startsWith('DX de')) {
    node.status({ fill:'grey', shape:'ring', text: '['+src+'] '+line.substring(0,50) });
    return [null, null];
}

var re = /^DX de\s+([\w\d\/\-#]+):\s+([\d.]+)\s+([\w\d\/\-#]+)\s*(.*?)\s*(\d{4}Z?)?\s*$/i;
var m  = line.match(re);
if (!m) {
    node.status({ fill:'yellow', shape:'dot', text:'no match: '+line.substring(0,45) });
    return [null, null];
}

var spotter = m[1].toUpperCase();
var freqKHz = parseFloat(m[2]);
var dxCall  = m[3].toUpperCase();
var comment = (m[4] || '').trim();
var freqMHz = (freqKHz / 1000).toFixed(6);

// Callsign pattern validation — drop garbage like DE, RR73, QSY etc
var callRe = /^(?:[A-Z0-9]{1,4}\/)?(?:[A-Z]{1,2}[0-9]{1,2}|[2-9][A-Z]{1,2}[0-9])[A-Z]{1,4}(?:\/[A-Z0-9]{1,4})?$/;
if (!callRe.test(dxCall)) {
    node.status({fill:'yellow', shape:'ring', text:'invalid call: ' + dxCall});
    return [null, null];
}

var dedup    = flow.get('dedup') || {};
var now      = Date.now();
var dedupKey = dxCall + '_' + Math.round(freqKHz);
if (dedup[dedupKey] && (now - dedup[dedupKey]) < 60000) {
    node.status({ fill:'grey', shape:'ring', text:'dup: '+dxCall });
    return [null, null];
}
dedup[dedupKey] = now;
Object.keys(dedup).forEach(function(k) { if (now - dedup[k] > 120000) delete dedup[k]; });
flow.set('dedup', dedup);

function getMode(khz, cmt) {
    var c = cmt.toUpperCase();
    if (c.match(/\bFT8\b/))  return 'FT8';
    if (c.match(/\bFT4\b/))  return 'FT4';
    if (c.match(/\bRTTY\b/)) return 'RTTY';
    if (c.match(/\bPSK\b/))  return 'PSK31';
    if (c.match(/\bCW\b/))   return 'CW';
    if (c.match(/\bSSB\b/))  return (khz < 10000) ? 'LSB' : 'USB';
    if (c.match(/\bUSB\b/))  return 'USB';
    if (c.match(/\bLSB\b/))  return 'LSB';
    if (c.match(/\bAM\b/))   return 'AM';
    if (c.match(/\bFM\b/))   return 'FM';
    var ft8 = [1840,3573,7074,10136,14074,18100,21074,24915,28074,50313];
    for (var f=0;f<ft8.length;f++) { if (Math.abs(khz-ft8[f])<=3) return 'FT8'; }
    var cw = [[1800,1840],[3500,3600],[7000,7040],[10100,10150],[14000,14070],[18068,18110],[21000,21070],[24890,24920],[28000,28070]];
    for (var i=0;i<cw.length;i++) { if (khz>=cw[i][0]&&khz<=cw[i][1]) return 'CW'; }
    return (khz < 10000) ? 'LSB' : 'USB';
}
var mode = getMode(freqKHz, comment);

function getBand(f) {
    if (f>=1800&&f<=2000)   return '160M';
    if (f>=3500&&f<=4000)   return '80M';
    if (f>=5330&&f<=5410)   return '60M';
    if (f>=7000&&f<=7300)   return '40M';
    if (f>=10100&&f<=10150) return '30M';
    if (f>=14000&&f<=14350) return '20M';
    if (f>=18068&&f<=18168) return '17M';
    if (f>=21000&&f<=21450) return '15M';
    if (f>=24890&&f<=24990) return '12M';
    if (f>=28000&&f<=29700) return '10M';
    if (f>=50000&&f<=54000) return '6M';
    if (f>=144000&&f<=148000) return '2M';
    return '';
}
var band = getBand(freqKHz);
if (!band) return [null, null];

var seq = (flow.get('spotSeq') || 7000) + 1;
flow.set('spotSeq', seq);
var ts = Math.floor(Date.now() / 1000);
var cmd = 'C' + seq + '|spot add rx_freq=' + freqMHz + ' callsign=' + dxCall + ' mode=' + mode + ' comment=' + (comment || 'DX') + ' spotter_callsign=' + spotter + ' timestamp=' + ts + ' color=#FF00FCCC priority=2 lifetime_seconds=1200 source=DX-Spot\n';

node.status({ fill:'green', shape:'dot', text: '['+src+'] '+dxCall+' '+freqMHz+' '+mode });

msg.spot = { call:dxCall, freqKHz:freqKHz, freqMHz:freqMHz, band:band, mode:mode, spotter:spotter, comment:comment, src:src, flexCmd:cmd };
msg.payload = msg.spot;
return [null, msg];

if (!flow.get('dxccReady')) {
    node.status({fill:'grey', shape:'dot', text:'Paused — reference data loading...'});
    return null;
}

var prefixMap  = flow.get('dxccPrefixMap')  || {};
var exceptions = flow.get('dxccExceptions') || {};
var seedNames  = flow.get('dxccSeedNames')  || {};

if (Object.keys(prefixMap).length === 0) {
    node.status({fill:'yellow', shape:'dot', text:'Waiting for cty.xml...'});
    return null;
}

// Resolve DXCC ADIF number from callsign
// Handles portable calls: VK2/G7VJR, G7VJR/P, 9M2/VK2 etc.
function resolveDXCC(call) {
    call = call.toUpperCase();
    // Exact callsign exception first
    if (exceptions[call]) return exceptions[call];
    var parts = call.split('/');
    var bestDxcc = null, bestLen = 0;
    parts.forEach(function(part) {
        if (part.length <= 2) return; // skip /P /M /MM suffixes
        for (var len = Math.min(5, part.length); len >= 1; len--) {
            var pfx = part.substring(0, len);
            if (prefixMap[pfx]) {
                if (len > bestLen) { bestLen = len; bestDxcc = prefixMap[pfx]; }
                break;
            }
        }
    });
    return bestDxcc || parts[0].substring(0, 4);
}

var spot = msg.spot;
if (!spot) return null;

// Blacklist check
